#include<bits/stdc++.h>
using namespace std;
const int N=500005;
int n,a[N],f[N],siz[N];
long long w[N];
struct node
{
    int x,siz;
    long long w;
    bool operator<(const node other) const
    {
        return w*other.siz>siz*other.w;
    }
};
bool flag=0;
priority_queue<node> q;
void init()
{
    for(int i=0;i<=n;i++)
    {
        f[i]=i,siz[i]=1;
    }
}
int find(int x)
{
    if(f[x]==x)
    {
        return x;
    }
    return f[x]=find(f[x]);
}
void fun(int x,int y)
{
    int fx=find(x),fy=find(y);
    if(fx==fy)
    {
        cout<<"-1";
        flag=1;
        return ;
    }
    f[fx]=fy;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    init();
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        fun(a[i],i);
        if(flag)
        {
            return 0;
        }
    }
    for(int i=1;i<=n;i++)
    {
        cin>>w[i];
        q.push(node{i,1,w[i]});
    }
    init();
    long long ans=0;
    while(!q.empty())
    {
        node t=q.top();
        q.pop();
        int num=find(t.x);
        if(siz[num]!=t.siz)
        {
            continue;
        }
        int fa=find(a[num]);
        f[num]=fa;
        ans+=(1ll*siz[fa]*w[num]);
        siz[fa]+=siz[num];
        w[fa]+=w[num];
        if(fa!=0)
        {
            q.push(node{fa,siz[fa],w[fa]});
        }
    }
    cout<<ans;
    return 0;
}
